/**
 * Corgi Dashboard — PDF Document Viewer Panel
 *
 * Embeds a PDF via iframe/<object> with page nav and zoom,
 * or falls back to displaying extracted text content.
 */
import React, { useCallback, useRef, useState } from 'react';
import { Download, ZoomIn, ZoomOut, RotateCcw, FileText } from 'lucide-react';
import { SidePanel } from './SidePanel';
import { useContentPanel, type PdfContent } from './ContentPanelManager';
import MarkdownRenderer from '../chat/MarkdownRenderer';

/* ------------------------------------------------------------------ */
/*  Constants                                                          */
/* ------------------------------------------------------------------ */

const ZOOM_LEVELS = [0.5, 0.75, 1, 1.25, 1.5, 2] as const;
const DEFAULT_ZOOM_INDEX = 2; // 100%

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const PdfViewer: React.FC = () => {
  const { panelType, panelContent, closePanel } = useContentPanel();
  const [zoomIndex, setZoomIndex] = useState(DEFAULT_ZOOM_INDEX);
  const iframeRef = useRef<HTMLIFrameElement>(null);

  const zoomIn = useCallback(() => {
    setZoomIndex((prev) => Math.min(prev + 1, ZOOM_LEVELS.length - 1));
  }, []);

  const zoomOut = useCallback(() => {
    setZoomIndex((prev) => Math.max(prev - 1, 0));
  }, []);

  const resetZoom = useCallback(() => {
    setZoomIndex(DEFAULT_ZOOM_INDEX);
  }, []);

  if (panelType !== 'pdf') return null;

  const content = panelContent as PdfContent | null;
  if (!content) return null;

  const hasUrl = !!content.url;
  const zoom = ZOOM_LEVELS[zoomIndex];

  const handleDownload = () => {
    if (!content.url) return;
    const a = document.createElement('a');
    a.href = content.url;
    a.download = content.title ?? 'document.pdf';
    a.target = '_blank';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const headerActions = (
    <div className="flex items-center gap-1">
      {hasUrl && (
        <>
          <PdfButton onClick={zoomOut} title="Zoom out" disabled={zoomIndex === 0}>
            <ZoomOut size={14} />
          </PdfButton>
          <span
            style={{
              fontSize: 'var(--text-xs)',
              color: 'var(--text-muted)',
              minWidth: 36,
              textAlign: 'center',
            }}
          >
            {Math.round(zoom * 100)}%
          </span>
          <PdfButton onClick={zoomIn} title="Zoom in" disabled={zoomIndex === ZOOM_LEVELS.length - 1}>
            <ZoomIn size={14} />
          </PdfButton>
          <PdfButton onClick={resetZoom} title="Reset zoom">
            <RotateCcw size={14} />
          </PdfButton>
        </>
      )}
      {content.url && (
        <PdfButton onClick={handleDownload} title="Download PDF">
          <Download size={14} />
        </PdfButton>
      )}
    </div>
  );

  return (
    <SidePanel
      open
      onClose={closePanel}
      title={content.title ?? 'PDF Document'}
      headerActions={headerActions}
      defaultWidth={0.45}
    >
      {hasUrl ? (
        /* Embed PDF via iframe with <object> fallback */
        <div
          style={{
            width: '100%',
            height: '100%',
            minHeight: 400,
            overflow: 'auto',
            display: 'flex',
            justifyContent: 'center',
          }}
        >
          <div
            style={{
              width: `${zoom * 100}%`,
              height: '100%',
              minHeight: 400,
              transition: 'width 0.2s ease',
            }}
          >
            <object
              data={content.url}
              type="application/pdf"
              style={{
                width: '100%',
                height: '100%',
                minHeight: 600,
                border: 'none',
                borderRadius: 'var(--radius-md)',
              }}
            >
              <iframe
                ref={iframeRef}
                src={content.url}
                title={content.title ?? 'PDF'}
                style={{
                  width: '100%',
                  height: '100%',
                  minHeight: 600,
                  border: 'none',
                  borderRadius: 'var(--radius-md)',
                }}
              />
            </object>
          </div>
        </div>
      ) : content.textContent ? (
        /* Fallback: render extracted text content */
        <div>
          <div
            className="flex items-center gap-2 mb-3 px-3 py-2 rounded-md"
            style={{
              background: 'var(--bg-tertiary)',
              fontSize: 'var(--text-xs)',
              color: 'var(--text-muted)',
            }}
          >
            <FileText size={12} />
            Extracted text content (PDF not embeddable)
          </div>
          <MarkdownRenderer content={content.textContent} />
        </div>
      ) : (
        /* Error state */
        <div
          className="flex flex-col items-center justify-center gap-3 py-16"
          style={{ color: 'var(--text-muted)' }}
        >
          <div
            style={{
              width: 48,
              height: 48,
              borderRadius: 'var(--radius-full)',
              background: 'var(--bg-tertiary)',
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <FileText size={20} />
          </div>
          <p style={{ fontSize: 'var(--text-sm)' }}>PDF content unavailable</p>
        </div>
      )}
    </SidePanel>
  );
};

/* ------------------------------------------------------------------ */
/*  PDF Toolbar Button                                                 */
/* ------------------------------------------------------------------ */

const PdfButton: React.FC<{
  onClick: () => void;
  title: string;
  disabled?: boolean;
  children: React.ReactNode;
}> = ({ onClick, title, disabled, children }) => (
  <button
    onClick={onClick}
    title={title}
    disabled={disabled}
    className="p-1.5 rounded-md transition-colors"
    style={{
      color: disabled ? 'var(--border-default)' : 'var(--text-muted)',
      background: 'transparent',
      border: 'none',
      cursor: disabled ? 'default' : 'pointer',
      opacity: disabled ? 0.4 : 1,
      display: 'flex',
      alignItems: 'center',
    }}
    onMouseEnter={(e) => {
      if (!disabled) {
        (e.currentTarget as HTMLElement).style.background = 'var(--bg-tertiary)';
        (e.currentTarget as HTMLElement).style.color = 'var(--text-primary)';
      }
    }}
    onMouseLeave={(e) => {
      (e.currentTarget as HTMLElement).style.background = 'transparent';
      (e.currentTarget as HTMLElement).style.color = disabled ? 'var(--border-default)' : 'var(--text-muted)';
    }}
  >
    {children}
  </button>
);

export default PdfViewer;
